CATMathTransformation MRFNSDBehavior::ApplyTransformationToMathLineForAngle(double angle, CATMathLine lineAsAxisToApplyTransfo)
{
	double Angle_Pos = angle; //To measure from normal Add 90deg to given angle
	if (Angle_Pos < 0)
		Angle_Pos = 360 - CATFabs(Angle_Pos);

	CATMathTransformation MathTransfo(CATDegreeToRadian * Angle_Pos, lineAsAxisToApplyTransfo);

	return MathTransfo;

}

CATMathLine MRFNSDBehavior::CheckIfProfileIsInwardOrOutwardTowardsIntersection(CATMathLine &profileForPosAngle, CATMathLine &profileForNegAngle, CATBody_var &pRefCurve)
{
	bool isOutward = false;

	CATMathLine outPut = profileForPosAngle; //by default return posAngle

	if (!pRefCurve)
		return outPut;

	CATMathPoint profilePos_EndPointToCheck;
	profileForPosAngle.EvalPoint(1, profilePos_EndPointToCheck);

	CATMathPoint profileNeg_EndPointToCheck;
	profileForNegAngle.EvalPoint(1, profileNeg_EndPointToCheck);

	double loclMinDist_Pos = 0, loclMinDist_Neg = 0;


	CATMathPoint intersectCurveMidPoint = GetPointOnWire(pRefCurve, 0.5);
	loclMinDist_Pos = intersectCurveMidPoint.DistanceTo(profilePos_EndPointToCheck);
	loclMinDist_Neg = intersectCurveMidPoint.DistanceTo(profileNeg_EndPointToCheck);

	if (loclMinDist_Pos < loclMinDist_Neg) //Check if profile is outward using min distance. if min distance which is greater that is the required output
		outPut = profileForPosAngle;
	else
		outPut = profileForNegAngle;
	//}

	return outPut;
}

