		sweepOperator->SetProfilePositionType(2);
		sweepOperator->SetProfileAutomaticCouplingMode(CATFrFTopologicalSweepAutomaticCoupling_D1);

		sweepOperator->Run();

		result = sweepOperator->GetResult();

